const trigger = $input.first().json || {};
const body = trigger.body || trigger;

const coerce = (value) => {
  if (Array.isArray(value)) return value;
  if (typeof value === 'string') {
    const trimmed = value.trim();
    if (!trimmed) return [];
    if (trimmed.startsWith('[') && trimmed.endsWith(']')) {
      try {
        const parsed = JSON.parse(trimmed);
        if (Array.isArray(parsed)) return parsed;
      } catch (error) {}
    }
    if (trimmed.includes(',')) return trimmed.split(',').map((v) => v.trim());
    return [trimmed];
  }
  if (value !== undefined && value !== null) return [value];
  return [];
};

const toBool = (value) => {
  if (typeof value === 'boolean') return value;
  if (typeof value === 'number') return value !== 0;
  const s = String(value || '').trim().toLowerCase();
  return s === 'true' || s === '1' || s === 'yes' || s === 'on';
};

let keys = coerce(body.keys ?? body.site_ids ?? body.site_id ?? body.id);
keys = keys
  .map((v) => String(v || '').trim())
  .filter((v) => v && v !== 'undefined' && v !== 'null');

if (!keys.length) throw new Error('keys/site_id missing');

const force = toBool(body.force ?? body.force_create);

return keys.map((site_id) => ({
  json: {
    site_id,
    force,
    requested_at: new Date().toISOString(),
    ai_model: String(body.ai_model || 'google/gemini-2.5-flash').trim() || 'google/gemini-2.5-flash'
  }
}));

const row = ($json && typeof $json.data === 'object') ? $json.data : $json;
if (!row || row.id === undefined || row.id === null) throw new Error('Site not found');

let niche = {};
if (row.niche_data && typeof row.niche_data === 'object') niche = row.niche_data;
if (typeof row.niche_data === 'string') {
  try {
    const parsed = JSON.parse(row.niche_data);
    if (parsed && typeof parsed === 'object') niche = parsed;
  } catch (error) {}
}

return {
  json: {
    site_id: String(row.id),
    site_name: String(row.site_name || '').trim(),
    main_product: String(row.main_product || '').trim(),
    site_domain: String(row.site_domain || '').trim(),
    current_log: String(row.log || ''),
    niche_data: niche,
    force: $('Normalize Request').item.json.force === true,
    ai_model: $('Normalize Request').item.json.ai_model
  }
};

const mainProduct = String($json.main_product || '').trim();
const siteName = String($json.site_name || '').trim();
const niche = String($json?.niche_data?.niche || '').trim();

const selectedAudience = String($json.selected_audience || $json?.niche_data?.target_audience || '').trim();
const audienceCandidates = Array.isArray($json.audience_candidates)
  ? $json.audience_candidates.map((v) => String(v || '').trim()).filter(Boolean).slice(0, 5)
  : [];

const baseTopic = (mainProduct || siteName || niche).trim();
if (!baseTopic) throw new Error('main_product/site_name/niche are all empty');

const systemPrompt = [
  'You are a senior domain naming strategist for content/affiliate websites.',
  'Generate niche-relevant, trustworthy, professional domains aligned with E-E-A-T (Experience, Expertise, Authoritativeness, Trustworthiness).',
  'Output strictly JSON only: {"items":[{"domain":"BestCoffeeHub.com","site_name":"Best Coffee Hub"}]}',
  'Hard rules:',
  '1) .com ONLY (no other TLDs).',
  '2) Exactly 20 unique items.',
  '3) domain must use English letters only (a-z/A-Z) in second-level name; no hyphens, no numbers, no special characters, no spaces.',
  '4) Use PascalCase in domain for readability (e.g., BestCoffeeHub.com).',
  '5) site_name must be the domain split into words with spaces, and each word must be Title Case (e.g., Best Coffee Hub).',
  '6) site_name must correspond to the returned domain words.',
  '7) Prioritize clarity, credibility, and topical relevance to the niche/main product.',
  '8) Avoid trademark-heavy or famous brand terms.',
  '9) Tailor naming tone to the chosen target audience.',
  '10) English-only words and ASCII letters only; do not use Chinese, Japanese, Korean, accented characters, or transliteration.',
  '11) Forbidden token in domain: the exact word \'domain\' must not appear anywhere in second-level domain.',
  '12) Return strict JSON only.'
].join('\n');

const userPrompt = [
  `main_product: ${mainProduct || '(empty)'}`,
  `site_name: ${siteName || '(empty)'}`,
  `niche: ${niche || '(empty)'}`,
  `selected_target_audience: ${selectedAudience || '(empty)'}`,
  `audience_candidates: ${audienceCandidates.length ? audienceCandidates.join(' | ') : '(empty)'}`,
  `current_site_domain: ${$json.site_domain || '(empty)'}`,
  '',
  'Task:',
  'Generate 20 brandable domain candidates for this niche and selected target audience.',
  'For each candidate, return domain (PascalCase .com) and site_name (same words with spaces, each word Title Case).',
  'Return JSON only.'
].join('\n');

return {
  json: {
    ...$json,
    target_audience_selected: selectedAudience,
    audience_candidates: audienceCandidates,
    system_prompt: systemPrompt,
    user_prompt: userPrompt
  }
};

const base = $('Build Prompt').item.json;
const raw = $json || {};

const normalizeDomain = (input) => {
  if (input === undefined || input === null) return null;

  let value = String(input).trim();
  if (!value) return null;

  value = value
    .replace(/^https?:\/\//i, '')
    .replace(/\/.*/, '')
    .replace(/\.$/, '');

  const host = value.split('@').pop() || value;
  const namePart = host.includes('.') ? host.split('.').slice(0, -1).join('.') : host;
  const name = String(namePart || '').replace(/[^a-zA-Z]/g, '').toLowerCase();

  if (!name || name.length < 4) return null;
  return `${name}.com`;
};

const toTitleCase = (value) => {
  const words = String(value || '')
    .trim()
    .split(/\s+/)
    .filter(Boolean);

  if (!words.length) return '';

  return words
    .map((word) => {
      const s = String(word || '').replace(/[^a-zA-Z0-9]/g, '');
      if (!s) return '';
      return s.charAt(0).toUpperCase() + s.slice(1).toLowerCase();
    })
    .filter(Boolean)
    .join(' ')
    .slice(0, 80)
    .trim();
};

const domainToSiteName = (domain) => {
  let value = String(domain || '').trim();
  if (!value) return '';

  value = value
    .replace(/^https?:\/\//i, '')
    .replace(/\/.*/, '');

  if (value.includes('.')) {
    const parts = value.split('.');
    if (parts.length > 1) value = parts.slice(0, -1).join('.');
  }

  const segmented = value
    .replace(/([a-z0-9])([A-Z])/g, '$1 $2')
    .replace(/[^a-zA-Z0-9]+/g, ' ')
    .trim();

  return toTitleCase(segmented);
};

const parseAiText = (payload) => {
  let text = payload?.choices?.[0]?.message?.content || payload?.text || payload?.output || payload?.response?.text;
  if (!text && payload?.candidates?.[0]?.content?.parts?.[0]?.text) {
    text = payload.candidates[0].content.parts[0].text;
  }
  if (!text || typeof text !== 'string') return { text: '', parsed: null };

  const cleaned = text.trim()
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '');

  try {
    return { text: cleaned, parsed: JSON.parse(cleaned) };
  } catch (error) {
    return { text: cleaned, parsed: null };
  }
};

const makeFallbackItems = () => {
  const rawSeed = String(base.main_product || base.site_name || '').trim();
  const seedWords = rawSeed
    .replace(/[^a-zA-Z0-9]+/g, ' ')
    .trim()
    .split(/\s+/)
    .filter(Boolean)
    .map((w) => w.toLowerCase());

  if (!seedWords.length) return [];

  const cap = (w) => w.charAt(0).toUpperCase() + w.slice(1);
  const root = seedWords.map(cap).join('');

  const bases = [
    root,
    `${root}Guide`,
    `${root}Insider`,
    `${root}Central`,
    `${root}Expert`,
    `Trusted${root}`,
    `Pure${root}`,
    `Best${root}`,
    `${root}World`,
    `${root}Hub`,
    `${root}Lab`,
    `${root}Home`,
    `${root}Today`,
    `${root}Focus`,
    `${root}Pro`,
    `${root}Advisor`,
    `${root}Insight`,
    `${root}Source`,
    `${root}Choice`,
    `${root}Life`
  ];

  return bases.map((name) => ({
    domain: `${name}.com`,
    site_name: domainToSiteName(name)
  }));
};

const coerceItems = (payload, parsed, text) => {
  if (payload && Array.isArray(payload.items)) return payload.items;
  if (payload && Array.isArray(payload.domains)) return payload.domains.map((d) => ({ domain: d }));
  if (payload && payload.data && Array.isArray(payload.data.items)) return payload.data.items;
  if (payload && payload.data && Array.isArray(payload.data.domains)) {
    return payload.data.domains.map((d) => ({ domain: d }));
  }

  if (parsed && Array.isArray(parsed.items)) return parsed.items;
  if (parsed && Array.isArray(parsed.domains)) return parsed.domains.map((d) => ({ domain: d }));
  if (Array.isArray(parsed)) return parsed;

  if (text) {
    const lines = text
      .split('\n')
      .map((line) => line.replace(/^[-*\d.)\s]+/, '').trim())
      .filter(Boolean);

    return lines.map((line) => ({ domain: line }));
  }

  return [];
};

let aiItems = [];
let aiMessage = '';

if (raw.error) {
  aiMessage = String(raw.error.message || raw.message || 'AI request failed');
} else {
  const { text, parsed } = parseAiText(raw);
  aiMessage = text || '';
  aiItems = coerceItems(raw, parsed, text);
}

if (!aiItems.length) aiItems = makeFallbackItems();

const seen = new Set();
const candidates = [];
const siteNameMap = {};

const pushItem = (entry) => {
  const domainInput = typeof entry === 'object' && entry !== null
    ? (entry.domain ?? entry.url ?? entry.name ?? '')
    : entry;

  const siteNameInput = typeof entry === 'object' && entry !== null
    ? (entry.site_name ?? entry.siteName ?? '')
    : '';

  const normalizedDomain = normalizeDomain(domainInput);
  if (!normalizedDomain || seen.has(normalizedDomain)) return;

  const computedSiteName = toTitleCase(siteNameInput) || domainToSiteName(domainInput || normalizedDomain);
  if (!computedSiteName) return;

  seen.add(normalizedDomain);
  candidates.push(normalizedDomain);
  siteNameMap[normalizedDomain] = computedSiteName;
};

for (const entry of aiItems) {
  pushItem(entry);
  if (candidates.length >= 20) break;
}

if (candidates.length < 20) {
  for (const entry of makeFallbackItems()) {
    pushItem(entry);
    if (candidates.length >= 20) break;
  }
}

if (!candidates.length) throw new Error('No valid .com domains generated under letters-only policy');

return {
  json: {
    ...base,
    candidates,
    site_name_map: siteNameMap,
    ai_message: aiMessage ? String(aiMessage).slice(0, 1000) : 'ok'
  }
};

const base = $('Parse AI Domains').item.json;
const resp = $json || {};

const now = new Date().toISOString();
const candidates = Array.isArray(base.candidates) ? base.candidates : [];
const force = base.force === true || String(base.force || '').toLowerCase() === 'true';
const currentDomainRaw = String(base.site_domain || '').trim();
const currentDomain = currentDomainRaw.toLowerCase();
const siteNameMap = (base.site_name_map && typeof base.site_name_map === 'object' && !Array.isArray(base.site_name_map))
  ? base.site_name_map
  : {};

const resultRows = Array.isArray(resp.domains) ? resp.domains : [];

const isPremium = (row) => {
  if (!row || typeof row !== 'object') return false;
  if (row.premium === true || row.isPremium === true || row.premiumDomain === true) return true;

  const pp = row.premiumPricing;
  if (Array.isArray(pp)) return pp.length > 0;
  if (pp && typeof pp === 'object') return Object.keys(pp).length > 0;
  if (typeof pp === 'number') return pp > 0;
  if (typeof pp === 'string') {
    const t = pp.trim();
    return t !== '' && t !== '0' && t.toLowerCase() !== 'false' && t.toLowerCase() !== 'null';
  }

  return false;
};

const availabilityMap = new Map();
for (const row of resultRows) {
  const domain = String(row?.domain || '').toLowerCase();
  if (!domain) continue;

  const result = String(row?.result || row?.status || '').toLowerCase();
  const available = row?.available === true || result === 'available';
  const premium = isPremium(row);

  availabilityMap.set(domain, {
    available,
    premium,
    result,
    message: row?.message || row?.reason || result || ''
  });
}

let selectedDomain = null;
const availableDomains = [];
const premiumAvailableDomains = [];
for (const d of candidates) {
  const key = String(d).toLowerCase();
  const info = availabilityMap.get(key);
  if (!info?.available) continue;

  if (info.premium) {
    premiumAvailableDomains.push(d);
    continue;
  }

  availableDomains.push(d);
}

if (availableDomains.length) {
  if (force && currentDomain) {
    const different = availableDomains.find((d) => String(d).toLowerCase() !== currentDomain);
    selectedDomain = different || availableDomains[0];
  } else {
    selectedDomain = availableDomains[0];
  }
}

let status = 'unavailable';
let availableFlag = false;
let message = `Checked ${candidates.length} domains; no standard-price domain available. Existing site_domain kept unchanged.`;

if (resp.error) {
  status = 'error';
  availableFlag = null;
  message = String(resp.error?.message || resp.message || 'Spaceship request failed').slice(0, 1000);
} else if (selectedDomain) {
  status = 'available';
  availableFlag = true;
  if (force) {
    if (currentDomain && String(selectedDomain).toLowerCase() === currentDomain) {
      message = `Force enabled; only current domain available in standard list. Kept: ${selectedDomain}`;
    } else if (currentDomain) {
      message = `Force enabled; replaced ${currentDomainRaw} with ${selectedDomain} (standard available: ${availableDomains.length}).`;
    } else {
      message = `Force enabled; selected ${selectedDomain} from ${availableDomains.length} standard available domain(s).`;
    }
  } else if (currentDomain) {
    message = `Found ${availableDomains.length} standard available domain(s). Force disabled; kept existing domain ${currentDomainRaw}. Top candidate: ${selectedDomain}`;
  } else {
    message = `Found ${availableDomains.length} standard available domain(s). Selected: ${selectedDomain}`;
  }

  if (premiumAvailableDomains.length) {
    message += ` Ignored ${premiumAvailableDomains.length} premium domain(s).`;
  }
} else if (premiumAvailableDomains.length) {
  status = 'unavailable';
  availableFlag = false;
  message = `Only premium domains are available (${premiumAvailableDomains.length}); existing site_domain kept unchanged.`;
}

const selectedAudience = String(base.target_audience_selected || base.selected_audience || '').trim();
const audienceCandidates = Array.isArray(base.audience_candidates)
  ? base.audience_candidates.map((v) => String(v || '').trim()).filter(Boolean).slice(0, 5)
  : [];

const appliedDomain = force ? (selectedDomain || currentDomainRaw || null) : (currentDomainRaw || selectedDomain || null);
const stamp = now.replace('T', ' ').replace('Z', ' UTC');
const logLines = [
  `[${stamp}] [AI-Domain] force=${force}; audience=${selectedAudience || '-'}; status=${status}; current=${currentDomainRaw || '-'}; selected=${selectedDomain || '-'}; applied=${appliedDomain || '-'}; standard_available=${availableDomains.length}/${candidates.length}; premium_available=${premiumAvailableDomains.length}`,
  `[AI-Domain] selected_audience=${selectedAudience || '-'}`,
  `[AI-Domain] audience_candidates=${audienceCandidates.join(' | ') || '-'}`,
  `[AI-Domain] candidates=${candidates.join(', ') || '-'}`,
  `[AI-Domain] available_domains=${availableDomains.join(', ') || '-'}`,
  `[AI-Domain] premium_available_domains=${premiumAvailableDomains.join(', ') || '-'}`,
  `[AI-Domain] availability_rows=${JSON.stringify(resultRows)}`,
  `[AI-Domain] message=${String(message).slice(0, 500)}`
];
const newLogEntry = logLines.join('\n');
const prevLog = String(base.current_log || '').trim();
const mergedLog = prevLog ? `${prevLog}\n\n${newLogEntry}` : newLogEntry;

let nextNicheData = {};
if (base.niche_data && typeof base.niche_data === 'object' && !Array.isArray(base.niche_data)) {
  nextNicheData = { ...base.niche_data };
}

// Keep only target_audience from this workflow in niche_data.
delete nextNicheData.target_audience_candidates;
delete nextNicheData.target_audience_updated_at;
delete nextNicheData.domain_suggestions;
delete nextNicheData.domain_availability;
delete nextNicheData.domain_selected;
delete nextNicheData.domain_generation_at;
if (selectedAudience) {
  nextNicheData.target_audience = selectedAudience;
}

const payload = {
  domain_check_status: status,
  domain_check_available: availableFlag,
  domain_check_at: now,
  domain_check_message: String(message).slice(0, 1000),
  log: mergedLog.slice(-12000),
  niche_data: nextNicheData
};

if (selectedDomain) {
  if (force) {
    payload.site_domain = selectedDomain;
  } else if (!currentDomainRaw) {
    payload.site_domain = selectedDomain;
  }
}

return {
  json: {
    site_id: base.site_id,
    force,
    current_domain: currentDomainRaw || null,
    applied_domain: appliedDomain,
    payload,
    site_name_map: siteNameMap,
    selected_audience: selectedAudience,
    audience_candidates: audienceCandidates,
    selected_domain: selectedDomain,
    available_domains: availableDomains,
    premium_available_domains: premiumAvailableDomains,
    candidates
  }
};

const detail = $('Build Site Update Payload').item.json;
return {
  json: {
    site_id: detail.site_id,
    force: detail.force,
    current_domain: detail.current_domain,
    applied_domain: detail.applied_domain,
    selected_audience: detail.selected_audience || null,
    audience_candidates: detail.audience_candidates || [],
    selected_domain: detail.selected_domain,
    available_domains: detail.available_domains,
    checked_domains: detail.candidates,
    status: detail.payload.domain_check_status,
    message: detail.payload.domain_check_message
  }
};

const mainProduct = String($json.main_product || '').trim();
const siteName = String($json.site_name || '').trim();
const niche = String($json?.niche_data?.niche || '').trim();
const currentAudience = String($json?.niche_data?.target_audience || '').trim();

const baseTopic = (mainProduct || siteName || niche).trim();
if (!baseTopic) throw new Error('main_product/site_name/niche are all empty');

const systemPrompt = [
  'You are a market researcher for niche content websites.',
  'Generate exactly 5 distinct target audiences for the niche/product.',
  'Each audience should be specific, practical, and commercially relevant.',
  'Output strict JSON only: {"audiences":["..."]}',
  'Rules:',
  '1) Exactly 5 items',
  '2) All items must be unique',
  '3) Each item <= 12 words',
  '4) English only'
].join('\n');

const userPrompt = [
  `main_product: ${mainProduct || '(empty)'}`,
  `site_name: ${siteName || '(empty)'}`,
  `niche: ${niche || '(empty)'}`,
  `existing_target_audience: ${currentAudience || '(empty)'}`,
  '',
  'Task: Provide 5 target audience options for domain naming strategy.',
  'Return JSON only.'
].join('\n');

return {
  json: {
    ...$json,
    audience_system_prompt: systemPrompt,
    audience_user_prompt: userPrompt
  }
};

const base = $('Build Audience Prompt').item.json;
const raw = $json || {};

const toText = (payload) => {
  let text = payload?.choices?.[0]?.message?.content || payload?.text || payload?.output || payload?.response?.text;
  if (!text && payload?.candidates?.[0]?.content?.parts?.[0]?.text) {
    text = payload.candidates[0].content.parts[0].text;
  }
  return typeof text === 'string' ? text : '';
};

const parseJson = (text) => {
  if (!text) return null;
  const cleaned = text.trim()
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '');
  try {
    return JSON.parse(cleaned);
  } catch (error) {
    return null;
  }
};

const normalizeAudience = (value) => {
  const s = String(value || '').replace(/\s+/g, ' ').trim();
  if (!s) return null;
  return s.length > 80 ? s.slice(0, 80).trim() : s;
};

const makeFallback = () => {
  const product = String(base.main_product || base.site_name || 'this product').trim();
  return [
    `first-time ${product} buyers`,
    `busy families using ${product} daily`,
    `budget-conscious shoppers for ${product}`,
    `${product} enthusiasts comparing features`,
    `quality-focused home users of ${product}`
  ];
};

let audiences = [];
if (raw.error) {
  audiences = [];
} else {
  const text = toText(raw);
  const parsed = parseJson(text);

  if (parsed && Array.isArray(parsed.audiences)) {
    audiences = parsed.audiences;
  } else if (Array.isArray(parsed)) {
    audiences = parsed;
  } else if (text) {
    audiences = text.split('\n').map((line) => line.replace(/^[-*\d.)\s]+/, '').trim());
  }
}

const deduped = [];
const seen = new Set();
for (const item of audiences) {
  const v = normalizeAudience(item);
  if (!v) continue;
  const k = v.toLowerCase();
  if (seen.has(k)) continue;
  seen.add(k);
  deduped.push(v);
  if (deduped.length >= 5) break;
}

const fallback = makeFallback();
for (const item of fallback) {
  if (deduped.length >= 5) break;
  const v = normalizeAudience(item);
  const k = String(v || '').toLowerCase();
  if (!v || seen.has(k)) continue;
  seen.add(k);
  deduped.push(v);
}

if (!deduped.length) throw new Error('No audience candidates generated');

const selectedIndex = Math.floor(Math.random() * deduped.length);
const selectedAudience = deduped[selectedIndex];

return {
  json: {
    ...base,
    audience_candidates: deduped,
    selected_audience: selectedAudience,
    selected_audience_index: selectedIndex
  }
};

const items = $input.all();

const placeholder = '????????,?????';

const normalizeDomain = (input) => {
  if (input === undefined || input === null) return null;

  let value = String(input).trim();
  if (!value) return null;

  value = value
    .replace(/^https?:\/\//i, '')
    .replace(/\/.*/, '')
    .replace(/\.$/, '');

  const host = value.split('@').pop() || value;
  const namePart = host.includes('.') ? host.split('.').slice(0, -1).join('.') : host;
  const name = String(namePart || '').replace(/[^a-zA-Z]/g, '').toLowerCase();

  if (!name) return null;
  return `${name}.com`;
};

const toTitleCase = (value) => {
  const parts = String(value || '')
    .replace(/[^a-zA-Z0-9]+/g, ' ')
    .trim()
    .split(/\s+/)
    .filter(Boolean);

  if (!parts.length) return '';

  return parts
    .map((word) => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase())
    .join(' ')
    .slice(0, 80)
    .trim();
};

const domainToSiteName = (domain) => {
  let value = String(domain || '').trim();
  if (!value) return '';

  value = value
    .replace(/^https?:\/\//i, '')
    .replace(/\/.*/, '');

  if (value.includes('.')) {
    const parts = value.split('.');
    if (parts.length > 1) value = parts.slice(0, -1).join('.');
  }

  const segmented = value
    .replace(/([a-z0-9])([A-Z])/g, '$1 $2')
    .replace(/[^a-zA-Z0-9]+/g, ' ')
    .trim();

  return toTitleCase(segmented);
};

return items.map((item) => {
  const data = item.json || {};
  const payload = { ...(data.payload || {}) };

  const mapRaw = (data.site_name_map && typeof data.site_name_map === 'object' && !Array.isArray(data.site_name_map))
    ? data.site_name_map
    : {};

  const siteNameMap = Object.fromEntries(
    Object.entries(mapRaw)
      .map(([k, v]) => [String(k || '').trim().toLowerCase(), toTitleCase(v)])
      .filter(([k, v]) => k && v)
  );

  const effectiveDomain = String(
    payload.site_domain || data.applied_domain || data.current_domain || ''
  ).trim();

  if (effectiveDomain && effectiveDomain !== placeholder) {
    const normalized = normalizeDomain(effectiveDomain);
    const mapped = normalized ? siteNameMap[normalized] : '';
    const siteName = mapped || domainToSiteName(effectiveDomain);

    if (siteName) payload.site_name = siteName;
  }

  const out = { ...data, payload };
  delete out.json;

  return { json: out, pairedItem: item.pairedItem };
});
